%pyspark
# English semantic similarity demo

w2v_en_model = model_w2v_en.stages[0]

# Same idea as the Schinese version — show off learned semantic relationships
test_words = ["good", "bad", "fun", "buggy", "recommend", "refund"]

for word in test_words:
    try:
        similar = w2v_en_model.findSynonyms(word, 8).collect()
        print(f"\nWords similar to '{word}':")
        for row in similar:
            print(f"  {row['word']:<25s}  similarity={row['similarity']:.4f}")
    except Exception as e:
        print(f"\n'{word}' not in vocabulary or error: {e}")
